import { ErrorHandler, Injectable, inject } from '@angular/core';

import { BoundaryStateService } from './boundary-state.service';

@Injectable()
export class BoundaryErrorHandler implements ErrorHandler {
  private readonly state = inject(BoundaryStateService);
  private readonly parent = inject(ErrorHandler, { optional: true, skipSelf: true });

  handleError(error: unknown): void {
    this.state.setError(error);
    this.parent?.handleError(error);
  }
}

import { Injectable, signal } from '@angular/core';

@Injectable()
export class BoundaryStateService {
  readonly error = signal<unknown | null>(null);

  setError(error: unknown) {
    this.error.set(error);
  }

  clear() {
    this.error.set(null);
  }
}

import { ErrorHandler, Injectable, inject } from '@angular/core';

import { GlobalErrorStateService } from './global-error-state.service';

@Injectable()
export class GlobalErrorHandler implements ErrorHandler {
  private readonly state = inject(GlobalErrorStateService);

  handleError(error: unknown): void {
    console.log(error);

    this.state.set(error);
    console.error(error);
  }
}

import { Injectable, signal } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class GlobalErrorStateService {
  readonly error = signal<unknown | null>(null);

  set(error: unknown) {
    this.error.set(error);
  }

  clear() {
    this.error.set(null);
  }
}

import { Injectable, signal } from '@angular/core';
import { ThemeEnum } from '../../model/enum/theme.enum';

type Mods = Record<string, boolean | string>;

@Injectable({
  providedIn: 'root',
})
export class UiService {
  private theme = signal<string>('light');

  constructor() {
    this.theme.set(localStorage.getItem('theme') ?? 'light');
  }

  public getTheme(): string {
    return this.theme();
  }

  public setTheme(): void {
    if (this.theme() === ThemeEnum.LIGHT) {
      this.theme.set(ThemeEnum.DARK);
    } else {
      this.theme.set(ThemeEnum.LIGHT);
    }
    localStorage.setItem('theme', this.theme());
  }

  public classNames(cls: string, mods: Mods = {}, additional: string[] = []): string {
    return [
      cls,
      ...additional,
      ...Object.entries(mods)
        .filter(([, value]) => Boolean(value))
        .map(([className]) => className),
    ].join(' ');
  }
}

