import { Component, inject } from '@angular/core';
import { RouterOutlet } from '@angular/router';
import { ErrorBoundaryComponent } from 'shared/error-boundary/error-boundary.component';
import { UiService } from 'shared/services/ui/ui-service';
import { NavbarComponent } from 'widgets/navbar/navbar.component';
import { SidebarComponent } from 'widgets/sidebar/sidebar.component';

@Component({
  selector: 'app-root',
  imports: [RouterOutlet, NavbarComponent, SidebarComponent, ErrorBoundaryComponent],
  templateUrl: './app.html',
  styleUrl: './app.scss',
})
export class App {
  uiService = inject(UiService);
}

import { Component, EventEmitter, inject, Input, Output } from '@angular/core';
import { UiService } from 'shared/services/ui/ui-service';
import { SpinnerComponent } from 'shared/spinner/spinner.component';

@Component({
  selector: 'app-button',
  imports: [SpinnerComponent],
  templateUrl: './button.component.html',
  styleUrl: './button.component.scss',
})
export class ButtonComponent {
  uiService = inject(UiService);

  @Input() label = '';
  @Input() type: 'button' | 'submit' | 'reset' = 'button';
  @Input() disabled = false;
  @Output() buttonClick: EventEmitter<MouseEvent> = new EventEmitter<MouseEvent>();
  @Input() loading = false;
  @Input() icon = '';
  @Input() iconPosition: 'left' | 'right' = 'left';
  @Input() iconSize: 'small' | 'medium' | 'large' = 'medium';
  @Input() iconColor = '';

  onClickHandler(event: MouseEvent): void {
    this.buttonClick.emit(event);
  }
}

import { Component, inject } from '@angular/core';

import { GlobalErrorStateService } from 'shared/services/error/global-error-state.service';

@Component({
  selector: 'app-error-boundary',
  standalone: true,
  templateUrl: './error-boundary.component.html',
  styleUrl: './error-boundary.component.scss',
})
export class ErrorBoundaryComponent {
  private readonly state = inject(GlobalErrorStateService);

  readonly error = this.state.error;

  reset() {
    this.state.clear();
  }

  errorMessage(err: unknown): string {
    if (err instanceof Error) return err.message || err.name;
    if (typeof err === 'string') return err;
    try {
      return JSON.stringify(err);
    } catch {
      return 'Unknown error';
    }
  }
}

